async function runAIStatusInference(task, layer1Findings, cwd2) {
  const prompt = buildStatusInferencePrompt(task, layer1Findings, cwd2);
  const options = {
    timeout: 120,
    allowedTools: [],
    outputFormat: "text",
    maxRetries: 0,
    cwd: cwd2
  };
  try {
    const result = await invokeAgent(prompt, options);
    if (!result.success) {
      return null;
    }
    const output = result.output.trim();
    const jsonMatch = output.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/) || output.match(/(\{[\s\S]*\})/);
    if (!jsonMatch)
      return null;
    const parsed = JSON.parse(jsonMatch[1]);
    if (!parsed.inferredStatus || typeof parsed.confidence !== "number") {
      return null;
    }
    const validStatuses = [
      "open",
      "in_progress",
      "wait_review",
      "wait_qa",
      "wait_evaluation",
      "resolved",
      "closed",
      "abandoned",
      "failed"
    ];
    if (!validStatuses.includes(parsed.inferredStatus)) {
      return null;
    }
    return {
      inferredStatus: parsed.inferredStatus,
      confidence: Math.max(0, Math.min(1, parsed.confidence)),
      reasoning: parsed.reasoning || "AI \u672A\u63D0\u4F9B\u4F9D\u636E",
      suggestion: parsed.suggestion || ""
    };
  } catch {
    return null;
  }
}
async function detectStatusInferenceIssues(task, cwd2, aiOptions) {
  const issues = [];
  const reportIssue = checkReportStatusConsistency(task.id, task, cwd2);
  if (reportIssue)
    issues.push(reportIssue);
  const checkpointIssue = checkCheckpointConsistency(task.id, task);
  if (checkpointIssue)
    issues.push(checkpointIssue);
  const qualityGateIssues = await checkQualityGateIssues(task.id, task, cwd2);
  issues.push(...qualityGateIssues);
  const evidenceIssue = checkMissingPipelineEvidence(task.id, task, cwd2);
  if (evidenceIssue)
    issues.push(evidenceIssue);
  const aiEnabled = aiOptions?.deepAnalyze && !aiOptions?.noAi;
  if (!aiEnabled)
    return issues;
  if (!shouldTriggerAIInference(task, issues, cwd2))
    return issues;
  const aiResult = await runAIStatusInference(task, issues, cwd2);
  if (!aiResult)
    return issues;
  const currentStatus = normalizeStatus(task.status);
  if (aiResult.inferredStatus !== currentStatus && aiResult.confidence >= 0.6) {
    issues.push({
      taskId: task.id,
      type: "ai_status_inference",
      severity: aiResult.confidence >= 0.8 ? "high" : "medium",
      message: `AI infers task status should be ${aiResult.inferredStatus} (current: ${currentStatus}, confidence: ${(aiResult.confidence * 100).toFixed(0)}%)`,
      suggestion: aiResult.suggestion || `Consider updating status to ${aiResult.inferredStatus}`,
      details: {
        layer: "L2",
        currentStatus,
        inferredStatus: aiResult.inferredStatus,
        confidence: aiResult.confidence,
        reasoning: aiResult.reasoning,
        layer1Issues: issues.filter((i) => i.type === "report_status_mismatch" || i.type === "checkpoint_status_mismatch" || i.type === "missing_pipeline_evidence").length
      }
    });
  }
  return issues;
}
