function calculateReopenStats(tasks) {
  const reopenCount = tasks.filter((t2) => (t2.reopenCount ?? 0) > 0).length;
  const reopenCounts = [];
  for (const task of tasks) {
    if (task.reopenCount && task.reopenCount > 0) {
      reopenCounts.push({
        taskId: task.id,
        title: task.title,
        count: task.reopenCount
      });
    } else if (task.history) {
      const reopenTimes = task.history.filter((h) => h.action === "status_change" && h.newValue === "reopened").length;
      if (reopenTimes > 0) {
        reopenCounts.push({
          taskId: task.id,
          title: task.title,
          count: reopenTimes
        });
      }
    }
  }
  reopenCounts.sort((a, b) => b.count - a.count);
  return { reopenCount, topReopened: reopenCounts };
}
function countArchivedTasks(cwd2) {
  const archiveDir = path15.join(getProjectDir(cwd2), "archive");
  if (!fs18.existsSync(archiveDir)) {
    return 0;
  }
  return fs18.readdirSync(archiveDir).filter((name) => fs18.statSync(path15.join(archiveDir, name)).isDirectory()).length;
}
function calculateHealthScore(result) {
  if (result.stats.total === 0)
    return 100;
  let score = 100;
  score -= result.stats.stale * 5;
  score -= result.stats.blocked * 3;
  score -= result.stats.cycle * 15;
  score -= result.stats.orphan * 1;
  score -= result.stats.abandonedResidual * 0.5;
  const noDescIssues = result.issues.filter((i) => i.type === "no_description").length;
  score -= noDescIssues * 0.5;
  return Math.max(0, Math.min(100, Math.round(score)));
}
function extractKeywordsFromCriteria(criteria) {
  const keywords = [];
  const stopWords = new Set([
    "\u7684",
    "\u548C",
    "\u4E0E",
    "\u6216",
    "\u5728",
    "\u662F",
    "\u6709",
    "\u4E3A",
    "\u4E86",
    "\u5BF9",
    "\u8FD9",
    "\u90A3",
    "the",
    "a",
    "an",
    "is",
    "are",
    "was",
    "were",
    "be",
    "been",
    "being",
    "have",
    "has",
    "had",
    "do",
    "does",
    "did",
    "will",
    "would",
    "could",
    "should",
    "may",
    "might",
    "must",
    "shall",
    "can",
    "to",
    "of",
    "in",
    "for",
    "on",
    "with",
    "at",
    "by",
    "from",
    "as",
    "into",
    "through",
    "\u6DFB\u52A0",
    "\u5B9E\u73B0",
    "\u786E\u4FDD",
    "\u9A8C\u8BC1",
    "\u5B8C\u6210",
    "\u68C0\u67E5",
    "\u66F4\u65B0",
    "\u4FEE\u6539",
    "\u914D\u7F6E",
    "add",
    "implement",
    "ensure",
    "verify",
    "complete",
    "check",
    "update",
    "option",
    "options",
    "\u529F\u80FD",
    "\u9009\u9879"
  ]);
  const englishWords = criteria.match(/[a-zA-Z][a-zA-Z0-9_-]*/g) || [];
  for (const word of englishWords) {
    const lower = word.toLowerCase();
    if (!stopWords.has(lower) && word.length > 2) {
      keywords.push(lower);
    }
  }
  const chineseWords = criteria.match(/[\u4e00-\u9fa5]{2,6}/g) || [];
  for (const word of chineseWords) {
    if (!stopWords.has(word)) {
      keywords.push(word);
    }
  }
  const identifiers = criteria.match(/[a-zA-Z_][a-zA-Z0-9_]+/g) || [];
  for (const id of identifiers) {
    if (id.length > 3 && !stopWords.has(id.toLowerCase())) {
      keywords.push(id);
    }
  }
  return [...new Set(keywords)];
}
function searchCodebaseForCriteria(criteria, cwd2) {
  const results = [];
  const keywords = extractKeywordsFromCriteria(criteria);
  if (keywords.length === 0) {
    return results;
  }
  const excludeDirs = new Set([
    "node_modules",
    "dist",
    "build",
    ".git",
    ".projmnt4claude",
    "coverage",
    ".next",
    ".nuxt",
    "out",
    "tmp",
    "temp"
  ]);
  const priorityExtensions = new Set([
    ".ts",
    ".tsx",
    ".js",
    ".jsx",
    ".vue",
    ".py",
    ".go",
    ".java",
    ".rs"
  ]);
  function searchDirectory(dir, depth = 0) {
    if (depth > 10)
      return;
    try {
      const entries = fs18.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path15.join(dir, entry.name);
        if (entry.isDirectory()) {
          if (excludeDirs.has(entry.name) || entry.name.startsWith(".")) {
            continue;
          }
          searchDirectory(fullPath, depth + 1);
        } else if (entry.isFile()) {
          const ext = path15.extname(entry.name);
          if (!priorityExtensions.has(ext)) {
            continue;
          }
          try {
            const content = fs18.readFileSync(fullPath, "utf-8");
            const lines = content.split(`
`);
            const matchedKeywords = [];
            const lineNumbers = [];
            for (const keyword of keywords) {
              const regex = new RegExp(escapeRegExp(keyword), "gi");
              let hasMatch = false;
              lines.forEach((line, index) => {
                if (regex.test(line)) {
                  hasMatch = true;
                  if (!lineNumbers.includes(index + 1)) {
                    lineNumbers.push(index + 1);
                  }
                }
              });
              if (hasMatch) {
                matchedKeywords.push(keyword);
              }
            }
            if (matchedKeywords.length > 0) {
              const uniqueKeywordRatio = matchedKeywords.length / keywords.length;
              const matchDensity = lineNumbers.length / Math.max(lines.length, 1);
              const relevanceScore = (uniqueKeywordRatio * 0.7 + matchDensity * 0.3) * 100;
              results.push({
                filePath: path15.relative(cwd2, fullPath),
                lineNumbers: lineNumbers.slice(0, 10),
                matchedKeywords,
                relevanceScore: Math.round(relevanceScore)
              });
            }
          } catch {}
        }
      }
    } catch {}
  }
  function escapeRegExp(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  }
  searchDirectory(cwd2);
  results.sort((a, b) => b.relevanceScore - a.relevanceScore);
  return results.slice(0, 10);
}
function generateSmartCheckpoints(taskId, criteria, searchResults, index) {
  const now = new Date().toISOString();
  const id = generateCheckpointId(taskId, index, criteria);
  const verificationMethod = inferSmartVerificationMethod(criteria, searchResults);
  const verificationCommands = inferVerificationCommands(criteria, searchResults);
  const checkpoint = {
    id,
    description: criteria,
    status: "pending",
    verification: {
      method: verificationMethod,
      commands: verificationCommands
    },
    createdAt: now,
    updatedAt: now
  };
  if (searchResults.length > 0) {
    checkpoint.verification.evidencePath = searchResults.slice(0, 3).map((r) => r.filePath).join(", ");
  }
  return checkpoint;
}
function inferSmartVerificationMethod(criteria, searchResults) {
  const lowerCriteria = criteria.toLowerCase();
  if (lowerCriteria.includes("\u6D4B\u8BD5") || lowerCriteria.includes("test")) {
    if (lowerCriteria.includes("e2e") || lowerCriteria.includes("\u7AEF\u5230\u7AEF")) {
      return "e2e_test";
    }
    if (lowerCriteria.includes("\u96C6\u6210") || lowerCriteria.includes("integration")) {
      return "integration_test";
    }
    return "unit_test";
  }
  if (lowerCriteria.includes("\u5BA1\u67E5") || lowerCriteria.includes("review") || lowerCriteria.includes("\u4EE3\u7801\u8D28\u91CF") || lowerCriteria.includes("\u91CD\u6784")) {
    return "code_review";
  }
  if (lowerCriteria.includes("api") || lowerCriteria.includes("\u63A5\u53E3")) {
    return "functional_test";
  }
  if (lowerCriteria.includes("ui") || lowerCriteria.includes("\u754C\u9762") || lowerCriteria.includes("\u9875\u9762") || lowerCriteria.includes("\u7EC4\u4EF6")) {
    return "e2e_test";
  }
  if (lowerCriteria.includes("\u67B6\u6784") || lowerCriteria.includes("architecture") || lowerCriteria.includes("\u8BBE\u8BA1") || lowerCriteria.includes("design")) {
    return "architect_review";
  }
  if (searchResults.length > 0) {
    const filePaths = searchResults.map((r) => r.filePath.toLowerCase()).join(" ");
    if (filePaths.includes("test") || filePaths.includes("spec")) {
      return "unit_test";
    }
    if (filePaths.includes("api") || filePaths.includes("route") || filePaths.includes("controller")) {
      return "functional_test";
    }
    if (filePaths.includes("component") || filePaths.includes("page") || filePaths.includes("view")) {
      return "e2e_test";
    }
    if (filePaths.includes("config") || filePaths.includes("setting")) {
      return "automated";
    }
  }
  return "automated";
}
function inferVerificationCommands(criteria, searchResults) {
  const commands = [];
  const lowerCriteria = criteria.toLowerCase();
  if (lowerCriteria.includes("\u6784\u5EFA") || lowerCriteria.includes("build")) {
    commands.push("npm run build");
  }
  if (lowerCriteria.includes("lint") || lowerCriteria.includes("\u4EE3\u7801\u89C4\u8303")) {
    commands.push("npm run lint");
  }
  if (lowerCriteria.includes("\u6D4B\u8BD5") || lowerCriteria.includes("test")) {
    commands.push("npm test");
  }
  if (lowerCriteria.includes("\u7C7B\u578B\u68C0\u67E5") || lowerCriteria.includes("type check")) {
    commands.push("npx tsc --noEmit");
  }
  if (searchResults.length > 0) {
    const hasTestFiles = searchResults.some((r) => r.filePath.includes("test") || r.filePath.includes("spec"));
    if (hasTestFiles && !commands.includes("npm test")) {
      commands.push("npm test");
    }
  }
  return commands;
}
function getContractPath(taskId, cwd2) {
  return path15.join(getTasksDir(cwd2), taskId, "contract.json");
}
function readContract(taskId, cwd2) {
  const contractPath = getContractPath(taskId, cwd2);
  if (!fs18.existsSync(contractPath)) {
    return null;
  }
  try {
    const content = fs18.readFileSync(contractPath, "utf-8");
    return JSON.parse(content);
  } catch {
    return null;
  }
}
function saveContract(taskId, contract, cwd2) {
  const contractPath = getContractPath(taskId, cwd2);
  const dir = path15.dirname(contractPath);
  if (!fs18.existsSync(dir)) {
    fs18.mkdirSync(dir, { recursive: true });
  }
  contract.updatedAt = new Date().toISOString();
  fs18.writeFileSync(contractPath, JSON.stringify(contract, null, 2), "utf-8");
}
function generateCheckpointsFromCriteria(taskId, acceptanceCriteria, taskTitle, cwd2 = process.cwd(), taskDescription) {
  const checkpoints = [];
  const now = new Date().toISOString();
  const analyzeConfig = readAnalyzeConfig(cwd2);
  const useSimpleMode = analyzeConfig.checkpointGenerator === "rule-based";
  const criteriaList = acceptanceCriteria && acceptanceCriteria.length > 0 ? acceptanceCriteria : generateDefaultCheckpoints(taskTitle || taskId, taskDescription);
  for (let index = 0;index < criteriaList.length; index++) {
    const criteria = criteriaList[index];
    const id = generateCheckpointId(taskId, index, criteria);
    if (useSimpleMode) {
      const method = inferVerificationMethod(criteria);
      checkpoints.push({
        id,
        description: criteria,
        status: "pending",
        verification: { method },
        createdAt: now,
        updatedAt: now
      });
    } else {
      const searchResults = searchCodebaseForCriteria(criteria, cwd2);
      const checkpoint = generateSmartCheckpoints(taskId, criteria, searchResults, index);
      checkpoint.createdAt = now;
      checkpoint.updatedAt = now;
      checkpoint.status = "pending";
      checkpoints.push(checkpoint);
    }
  }
  return checkpoints;
}
function inferVerificationMethod(description) {
  const lowerDesc = description.toLowerCase();
  if (lowerDesc.includes("\u6D4B\u8BD5") || lowerDesc.includes("test")) {
    return "unit_test";
  }
  if (lowerDesc.includes("\u5BA1\u67E5") || lowerDesc.includes("review") || lowerDesc.includes("\u4EE3\u7801\u8D28\u91CF")) {
    return "code_review";
  }
  if (lowerDesc.includes("api") || lowerDesc.includes("\u63A5\u53E3")) {
    return "functional_test";
  }
  if (lowerDesc.includes("ui") || lowerDesc.includes("\u754C\u9762") || lowerDesc.includes("\u9875\u9762")) {
    return "e2e_test";
  }
  if (lowerDesc.includes("\u6587\u6863") || lowerDesc.includes("document")) {
    return "automated";
  }
  return "automated";
}
function generateDefaultCheckpoints(taskTitle, taskDescription) {
  const content = taskDescription || taskTitle;
  const taskType = inferTaskType(taskTitle);
  const smartCheckpoints = inferCheckpointsFromDescription(content, taskType);
  if (smartCheckpoints.length > 0) {
    return smartCheckpoints;
  }
  return generateTitleBasedCheckpoints(taskTitle);
}
function generateTitleBasedCheckpoints(taskTitle) {
  const checkpoints = [];
  const identifierMatches = taskTitle.match(/\b[A-Z][a-zA-Z0-9]{2,}\b|\b[a-z][a-zA-Z0-9]*_[a-zA-Z0-9_]+\b/g);
  if (identifierMatches) {
    const uniqueIds = [...new Set(identifierMatches)].slice(0, 3);
    for (const id of uniqueIds) {
      checkpoints.push(`${id} \u76F8\u5173\u529F\u80FD\u5DF2\u5B9E\u73B0`);
    }
  }
  const fileMatches = taskTitle.match(/(?:src|lib|test|config)\/[\w/.-]+\.[a-z]+/g);
  if (fileMatches) {
    const uniqueFiles = [...new Set(fileMatches)].slice(0, 2);
    for (const file of uniqueFiles) {
      checkpoints.push(`${file} \u5305\u542B\u6240\u9700\u4FEE\u6539`);
    }
  }
  const actionPatterns = [
    [/\u4FEE\u590D|fix/i, "\u95EE\u9898\u5DF2\u5B9A\u4F4D\u5E76\u4FEE\u590D"],
    [/\u5B9E\u73B0|implement/i, "\u6838\u5FC3\u529F\u80FD\u5DF2\u5B9E\u73B0"],
    [/\u6DFB\u52A0|add/i, "\u65B0\u529F\u80FD\u5DF2\u6DFB\u52A0\u5E76\u53EF\u7528"],
    [/\u4F18\u5316|optimize/i, "\u6027\u80FD\u4F18\u5316\u5DF2\u5B8C\u6210\u5E76\u9A8C\u8BC1"],
    [/\u91CD\u6784|refactor/i, "\u91CD\u6784\u5B8C\u6210\uFF0C\u884C\u4E3A\u4E0D\u53D8"],
    [/\u96C6\u6210|integrate/i, "\u96C6\u6210\u5B8C\u6210\uFF0C\u63A5\u53E3\u8FDE\u901A"],
    [/\u8FC1\u79FB|migrate/i, "\u8FC1\u79FB\u5B8C\u6210\uFF0C\u529F\u80FD\u7B49\u4EF7"],
    [/\u914D\u7F6E|config/i, "\u914D\u7F6E\u5DF2\u751F\u6548"]
  ];
  for (const [pattern, checkpoint] of actionPatterns) {
    if (pattern.test(taskTitle)) {
      checkpoints.push(checkpoint);
      break;
    }
  }
  if (checkpoints.length < 2) {
    checkpoints.push(`${taskTitle.substring(0, 30)} \u76EE\u6807\u5DF2\u8FBE\u6210`);
    checkpoints.push("\u76F8\u5173\u4EE3\u7801\u5DF2\u901A\u8FC7\u9A8C\u8BC1");
  }
  return [...new Set(checkpoints)];
}
function extractAcceptanceCriteriaFromDescription(description) {
  const criteria = [];
  const lines = description.split(`
`);
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^[-*]\s*(?:\[[ x]\])?\s*(.+)/.test(trimmed) || /^\d+\.\s*(.+)/.test(trimmed)) {
      const match = trimmed.match(/^(?:[-*]|\d+\.)\s*(?:\[[ x]\])?\s*(.+)/);
      if (match && match[1]) {
        criteria.push(match[1].trim());
      }
    }
  }
  if (criteria.length === 0 && description.trim()) {
    criteria.push(description.trim());
  }
  return criteria;
}
function fixTaskCheckpoints(taskId, cwd2) {
  const task = readTaskMeta(taskId, cwd2);
  if (!task) {
    return { fixed: false, reason: "\u4EFB\u52A1\u4E0D\u5B58\u5728" };
  }
  let contract = readContract(taskId, cwd2);
  if (!contract) {
    const now = new Date().toISOString();
    contract = {
      taskId,
      acceptanceCriteria: [],
      verificationCommands: [],
      checkpoints: [],
      createdAt: now,
      updatedAt: now
    };
  }
  if (contract.checkpoints && contract.checkpoints.length > 0) {
    return { fixed: false, reason: "\u68C0\u67E5\u70B9\u5DF2\u5B58\u5728" };
  }
  let acceptanceCriteria = contract.acceptanceCriteria || [];
  if (acceptanceCriteria.length === 0 && task.description) {
    acceptanceCriteria = extractAcceptanceCriteriaFromDescription(task.description);
    contract.acceptanceCriteria = acceptanceCriteria;
  }
  const checkpoints = generateCheckpointsFromCriteria(taskId, acceptanceCriteria, task.title, cwd2, task.description);
  if (checkpoints.length === 0) {
    return { fixed: false, reason: "\u65E0\u6CD5\u751F\u6210\u68C0\u67E5\u70B9" };
  }
  contract.checkpoints = checkpoints.map((cp) => cp.id);
  syncCheckpointsToMeta(taskId, checkpoints, cwd2);
  saveContract(taskId, contract, cwd2);
  return { fixed: true, reason: `\u751F\u6210\u4E86 ${checkpoints.length} \u4E2A\u68C0\u67E5\u70B9` };
}
