function formatLogList(entries, verbose = false) {
  if (entries.length === 0) {
    return "\u6682\u65E0 batch-update \u64CD\u4F5C\u65E5\u5FD7";
  }
  const lines = [];
  lines.push("");
  lines.push(`\uD83D\uDCCB Batch Update \u64CD\u4F5C\u65E5\u5FD7 (\u5171 ${entries.length} \u6761)`);
  lines.push("\u2501".repeat(80));
  lines.push("");
  const sortedEntries = [...entries].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  for (const entry of sortedEntries.slice(0, 50)) {
    const time = new Date(entry.timestamp).toLocaleString("zh-CN");
    const command = entry.commandArgs.join(" ");
    const source = entry.source;
    const env = entry.context.envIndicators;
    const envTags = [];
    if (env.isVscode)
      envTags.push("VSCode");
    if (env.isCursor)
      envTags.push("Cursor");
    if (env.isJetbrains)
      envTags.push("JetBrains");
    if (env.isTmux)
      envTags.push("Tmux");
    if (env.isCi)
      envTags.push("CI");
    lines.push(`[${time}] ${source}${envTags.length > 0 ? " (" + envTags.join(", ") + ")" : ""}`);
    lines.push(`  \u547D\u4EE4: ${command}`);
    lines.push(`  \u4EFB\u52A1: ${entry.summary.updatedCount}/${entry.summary.totalCount} \u4E2A\u5DF2\u66F4\u65B0`);
    if (verbose && entry.tasks.length > 0) {
      for (const task of entry.tasks.slice(0, 5)) {
        const statusChange = task.oldStatus !== task.newStatus ? `${task.oldStatus} \u2192 ${task.newStatus}` : task.oldStatus;
        lines.push(`    - ${task.id}: ${statusChange}`);
      }
      if (entry.tasks.length > 5) {
        lines.push(`    ... \u8FD8\u6709 ${entry.tasks.length - 5} \u4E2A\u4EFB\u52A1`);
      }
    }
    lines.push("");
  }
  return lines.join(`
`);
}
function showLogSummary(cwd2 = process.cwd()) {
  const entries = queryBatchUpdateLogs({}, cwd2);
  if (entries.length === 0) {
    return "\u6682\u65E0 batch-update \u64CD\u4F5C\u65E5\u5FD7";
  }
  const lines = [];
  lines.push("");
  lines.push("\uD83D\uDCCA Batch Update \u65E5\u5FD7\u7EDF\u8BA1");
  lines.push("\u2501".repeat(80));
  lines.push("");
  const sourceCount = {};
  const dateCount = {};
  for (const entry of entries) {
    sourceCount[entry.source] = (sourceCount[entry.source] || 0) + 1;
    const date = entry.timestamp.split("T")[0];
    dateCount[date] = (dateCount[date] || 0) + 1;
  }
  lines.push("\u6309\u6765\u6E90\u7EDF\u8BA1:");
  for (const [source, count] of Object.entries(sourceCount).sort((a, b) => b[1] - a[1])) {
    lines.push(`  ${source}: ${count} \u6B21`);
  }
  lines.push("");
  lines.push("\u6309\u65E5\u671F\u7EDF\u8BA1 (\u6700\u8FD17\u5929):");
  const sortedDates = Object.entries(dateCount).sort().slice(-7);
  for (const [date, count] of sortedDates) {
    lines.push(`  ${date}: ${count} \u6B21`);
  }
  lines.push("");
  lines.push(`\u603B\u8BA1: ${entries.length} \u6761\u8BB0\u5F55`);
  lines.push("");
  return lines.join(`
`);
}

