function getStatusIcon(status) {
  const icons = {
    open: "\u2B1C",
    in_progress: "\uD83D\uDD04",
    wait_review: "\uD83D\uDC40",
    wait_qa: "\uD83E\uDDEA",
    wait_evaluation: "\u23F3",
    resolved: "\u2705",
    closed: "\u26AB",
    abandoned: "\u274C",
    failed: "\u26D4"
  };
  return icons[status] || "\u2753";
}
function getDisplayWidth(str) {
  let width = 0;
  for (const char of str) {
    const code = char.codePointAt(0);
    if (/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffef]/.test(char)) {
      width += 2;
    } else if (code > 65535) {
      width += 2;
    } else {
      width += 1;
    }
  }
  return width;
}
function truncateByDisplayWidth(str, maxDisplayWidth) {
  let result = "";
  let currentWidth = 0;
  for (const char of str) {
    const charWidth = /[\u4e00-\u9fff\u3000-\u303f\uff00-\uffef]/.test(char) ? 2 : 1;
    if (currentWidth + charWidth > maxDisplayWidth) {
      break;
    }
    result += char;
    currentWidth += charWidth;
  }
  return result;
}
function padByDisplayWidth(str, targetWidth) {
  const currentWidth = getDisplayWidth(str);
  if (currentWidth >= targetWidth) {
    return str;
  }
  return str + " ".repeat(targetWidth - currentWidth);
}
