function parseCommandMetadata(filePath) {
  try {
    const content = fs20.readFileSync(filePath, "utf-8");
    const frontmatterMatch = content.match(/^---\n(.*?)\n---/s);
    if (!frontmatterMatch) {
      return null;
    }
    const frontmatter = frontmatterMatch[1];
    const metadata = {
      description: "",
      "argument-hint": ""
    };
    const descriptionMatch = frontmatter.match(/description:\s*["'](.+?)["']/);
    if (descriptionMatch) {
      metadata.description = descriptionMatch[1];
    }
    const argumentMatch = frontmatter.match(/argument-hint:\s["'](.+?)["']/);
    if (argumentMatch) {
      metadata["argument-hint"] = argumentMatch[1];
    }
    return metadata;
  } catch (error) {
    return null;
  }
}
function getCommandsDir(cwd2) {
  const language = getLanguage(cwd2);
  const pluginRoot = process.env.CLAUDE_PLUGIN_ROOT;
  if (pluginRoot) {
    const localesDir = path17.join(pluginRoot, "locales", language, "commands");
    if (fs20.existsSync(localesDir)) {
      return localesDir;
    }
  }
  return path17.join(cwd2, "commands");
}
function getAvailableCommands(commandsDir) {
  try {
    const files = fs20.readdirSync(commandsDir);
    return files.filter((file) => file.endsWith(".md")).map((file) => file.replace(".md", "")).sort();
  } catch (error) {
    return [];
  }
}
